import { useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { propertiesData, getFilterOptions, filterProperties } from '../data/propertiesData';
import { Home, Building2, DollarSign, TrendingUp, Filter } from 'lucide-react';

const Projects = () => {
  const [filters, setFilters] = useState({
    category: 'All',
    listingType: 'All',
    propertyType: 'All',
    maxPrice: 50000000
  });
  const [showFilters, setShowFilters] = useState(false);
  
  const filterOptions = getFilterOptions();
  const filteredProperties = filterProperties(propertiesData, filters);
  
  const getCurrentPropertyTypes = () => {
    if (filters.category === 'Residential') return filterOptions.propertyTypes.Residential;
    if (filters.category === 'Commercial') return filterOptions.propertyTypes.Commercial;
    return ['All'];
  };
  
  const formatPrice = (price, listingType) => {
    if (listingType === 'Rent') {
      return `₹${price.toLocaleString('en-IN')}/month`;
    }
    if (listingType === 'Lease') {
      return `₹${price.toLocaleString('en-IN')}/year`;
    }
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} Lakhs`;
    return `₹${price.toLocaleString('en-IN')}`;
  };
  
  const getListingTypeColor = (type) => {
    switch(type) {
      case 'Sale': return 'bg-green-500';
      case 'Rent': return 'bg-blue-500';
      case 'Lease': return 'bg-purple-500';
      default: return 'bg-gray-500';
    }
  };
  
  const getCategoryIcon = (category) => {
    return category === 'Residential' ? <Home size={14} /> : <Building2 size={14} />;
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="pt-32 pb-16 bg-gray-50 min-h-screen"
    >
      <div className="container-custom">
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-[#0a192f] mb-4">Find Your Property</h1>
          <p className="text-gray-600">Discover residential & commercial properties in Nashik</p>
        </div>
        
        {/* Filter Toggle Button for Mobile */}
        <div className="lg:hidden mb-4">
          <button
            onClick={() => setShowFilters(!showFilters)}
            className="w-full bg-white border rounded-lg py-2 flex items-center justify-center gap-2"
          >
            <Filter size={18} /> {showFilters ? 'Hide Filters' : 'Show Filters'}
          </button>
        </div>
        
        <div className="grid lg:grid-cols-4 gap-8">
          {/* Filters Sidebar */}
          <div className={`lg:block ${showFilters ? 'block' : 'hidden'}`}>
            <div className="bg-white rounded-xl shadow-md p-5 sticky top-24">
              <h3 className="font-bold text-lg mb-4">Filter Properties</h3>
              
              {/* Category Filter */}
              <div className="mb-4">
                <label className="block text-sm font-semibold mb-2">Category</label>
                <select
                  value={filters.category}
                  onChange={(e) => setFilters({...filters, category: e.target.value, propertyType: 'All'})}
                  className="w-full p-2 border rounded-lg"
                >
                  {filterOptions.categories.map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>
              </div>
              
              {/* Listing Type Filter */}
              <div className="mb-4">
                <label className="block text-sm font-semibold mb-2">Listing Type</label>
                <select
                  value={filters.listingType}
                  onChange={(e) => setFilters({...filters, listingType: e.target.value})}
                  className="w-full p-2 border rounded-lg"
                >
                  {filterOptions.listingTypes.map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </select>
              </div>
              
              {/* Property Type Filter - Dynamic based on Category */}
              {(filters.category === 'Residential' || filters.category === 'Commercial') && (
                <div className="mb-4">
                  <label className="block text-sm font-semibold mb-2">Property Type</label>
                  <select
                    value={filters.propertyType}
                    onChange={(e) => setFilters({...filters, propertyType: e.target.value})}
                    className="w-full p-2 border rounded-lg"
                  >
                    {getCurrentPropertyTypes().map(type => (
                      <option key={type} value={type}>{type}</option>
                    ))}
                  </select>
                </div>
              )}
              
              {/* Price Filter */}
              <div className="mb-4">
                <label className="block text-sm font-semibold mb-2">Max Price</label>
                <input
                  type="range"
                  min="100000"
                  max="50000000"
                  step="100000"
                  value={filters.maxPrice}
                  onChange={(e) => setFilters({...filters, maxPrice: parseInt(e.target.value)})}
                  className="w-full"
                />
                <div className="flex justify-between mt-1">
                  <span className="text-xs text-gray-500">₹1L</span>
                  <span className="text-xs text-[#d4af37] font-semibold">
                    {filters.maxPrice >= 10000000 
                      ? `₹${(filters.maxPrice / 10000000).toFixed(1)}Cr` 
                      : `₹${(filters.maxPrice / 100000).toFixed(0)}L`}
                  </span>
                  <span className="text-xs text-gray-500">₹5Cr</span>
                </div>
              </div>
              
              <button
                onClick={() => setFilters({ category: 'All', listingType: 'All', propertyType: 'All', maxPrice: 50000000 })}
                className="w-full bg-gray-200 text-gray-700 py-2 rounded-lg hover:bg-gray-300 transition"
              >
                Reset Filters
              </button>
            </div>
          </div>
          
          {/* Properties Grid */}
          <div className="lg:col-span-3">
            <p className="text-gray-500 mb-4">Found {filteredProperties.length} properties</p>
            
            <div className="grid md:grid-cols-2 gap-6">
              {filteredProperties.map((property) => (
                <div key={property.id} className="bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-2xl transition hover:-translate-y-2">
                  <div className="relative h-48 overflow-hidden">
                    <img 
                      src={property.images[0]} 
                      alt={property.title}
                      className="w-full h-full object-cover transition-transform duration-500 hover:scale-110"
                    />
                    <div className="absolute top-3 left-3 flex gap-2">
                      <span className={`${getListingTypeColor(property.listingType)} text-white px-2 py-1 rounded-lg text-xs font-semibold flex items-center gap-1`}>
                        {getCategoryIcon(property.category)}
                        {property.listingType}
                      </span>
                    </div>
                    <div className="absolute top-3 right-3">
                      <span className="bg-[#d4af37] text-[#0a192f] px-2 py-1 rounded-lg text-xs font-semibold">
                        {property.category}
                      </span>
                    </div>
                  </div>
                  
                  <div className="p-4">
                    <h3 className="text-lg font-bold text-[#0a192f] mb-1">{property.title}</h3>
                    <p className="text-gray-500 text-sm mb-2">{property.location}</p>
                    <p className="text-[#d4af37] font-bold text-xl">
                      {formatPrice(property.price, property.listingType)}
                    </p>
                    
                    <div className="flex gap-3 mt-3 text-sm text-gray-500">
                      {property.bedrooms > 0 && <span>🛏️ {property.bedrooms} BHK</span>}
                      <span>📐 {property.area_sqft} sq.ft</span>
                    </div>
                    
                    <div className="mt-2 flex flex-wrap gap-1">
                      <span className="text-xs text-gray-400 border rounded-full px-2 py-0.5">{property.propertyType}</span>
                      {property.reraVerified && <span className="text-xs text-green-600 border border-green-200 rounded-full px-2 py-0.5">RERA</span>}
                    </div>
                    
                    <Link to={`/property/${property.id}`}>
                      <button className="w-full mt-4 bg-[#d4af37] text-[#0a192f] py-2 rounded-lg font-semibold hover:bg-opacity-90 transition">
                        View Details →
                      </button>
                    </Link>
                  </div>
                </div>
              ))}
            </div>
            
            {filteredProperties.length === 0 && (
              <div className="text-center py-12 bg-white rounded-xl">
                <p className="text-gray-500">No properties match your filters.</p>
                <button
                  onClick={() => setFilters({ category: 'All', listingType: 'All', propertyType: 'All', maxPrice: 50000000 })}
                  className="mt-4 text-[#d4af37] hover:underline"
                >
                  Clear all filters
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default Projects;
